def parse_tool_payload(text):
    import json
    obj = json.loads(text)
    if "tool" not in obj or "args" not in obj:
        raise ValueError("Missing required keys: 'tool' and 'args'")
    return obj

def validate_person(obj):
    return (
        isinstance(obj, dict)
        and isinstance(obj.get("name"), str)
        and isinstance(obj.get("age"), int)
        and obj["age"] >= 0
    )
